    <script>
       function toggleNav() {
            const sidenav = document.getElementById("mySidenav");
            const main = document.getElementById("main");
            
            // If the sidebar is currently open, close it
            if (sidenav.style.width === "250px") {
                sidenav.style.width = "0";
                main.style.marginLeft = "0";
                localStorage.setItem('sidebarState', 'closed');
            } 
            // Otherwise, open it
            else {
                sidenav.style.width = "250px";
                main.style.marginLeft = "250px";
                localStorage.setItem('sidebarState', 'open');
            }
        }
        function toggleAccordion(menuId, element) {
            const submenu = document.getElementById(menuId);
            element.classList.toggle("open");
            if (submenu.style.maxHeight) {
                submenu.style.maxHeight = null;
                localStorage.setItem('stockSubmenuState', 'closed');
            } else {
                submenu.style.maxHeight = submenu.scrollHeight + "px";
                localStorage.setItem('stockSubmenuState', 'open');
            }
        }

        // On page load, check if the sidebar should be open and apply its state
        (function() {
            const sidenav = document.getElementById("mySidenav");
            const main = document.getElementById("main");
            const sidebarState = localStorage.getItem('sidebarState');

            if (sidebarState === 'open') {
                // To prevent the transition animation on page load, we temporarily disable it
                sidenav.style.transition = 'none';
                main.style.transition = 'none';

                // Set the sidebar to open
                sidenav.style.width = "250px";
                main.style.marginLeft = "250px";

                // Re-enable the transition after the initial state is set.
                // Using a timeout allows the browser to render the initial state without animation.
                setTimeout(function() {
                    sidenav.style.transition = '0.5s';
                    main.style.transition = 'margin-left .5s';
                }, 10);
            }
            // Restore Stock submenu state from localStorage
            const stockSubmenu = document.getElementById('stockSubmenu');
            const stockToggle = stockSubmenu.previousElementSibling;
            const submenuState = localStorage.getItem('stockSubmenuState');
            if (submenuState === 'open') {
                if (stockToggle) stockToggle.classList.add('open');
                stockSubmenu.style.transition = 'none';
                stockSubmenu.style.maxHeight = stockSubmenu.scrollHeight + "px";
                setTimeout(function() {
                    stockSubmenu.style.transition = 'max-height 0.3s ease-out';
                }, 10);
            }
        })();

    </script>
</html>